import Analytics from './Analytics';
import Friends from './Friends';
import Games from './Games';
import Profile from './Profile';
import Settings from './Settings';
import type { RendererApi, WalletSnapshot } from '@shared/types';

type MoreView = 'analytics' | 'settings' | 'friends' | 'profile' | 'games';

type Props = {
  section: MoreView;
  onSectionChange: (section: MoreView) => void;
  api: RendererApi;
  wallet: WalletSnapshot;
  theme: 'lavender' | 'olive';
  onThemeChange: (next: 'lavender' | 'olive') => void;
};

const MORE_ITEMS: Array<{ id: MoreView; label: string; hint: string }> = [
  { id: 'analytics', label: 'Analytics', hint: 'Trends, patterns, and history' },
  { id: 'settings', label: 'Settings', hint: 'Rules, themes, and thresholds' },
  { id: 'friends', label: 'Friends', hint: 'Social pressure and accountability' },
  { id: 'profile', label: 'Profile', hint: 'Trophies, identity, and setup' },
  { id: 'games', label: 'Games', hint: 'Contained breaks and coin sinks' }
];

export default function MorePanel({ section, onSectionChange, api, wallet, theme, onThemeChange }: Props) {
  return (
    <section className="panel more-panel">
      <header className="panel-header more-panel-header">
        <div>
          <p className="eyebrow">Secondary surfaces</p>
          <h1>More</h1>
          <p className="subtitle">The useful extras stay reachable without taking over the home screen.</p>
        </div>
      </header>

      <div className="more-panel-nav" role="tablist" aria-label="More sections">
        {MORE_ITEMS.map((item) => (
          <button
            key={item.id}
            type="button"
            role="tab"
            className={section === item.id ? 'active' : ''}
            aria-selected={section === item.id}
            onClick={() => onSectionChange(item.id)}
          >
            <span>{item.label}</span>
            <small>{item.hint}</small>
          </button>
        ))}
      </div>

      {section === 'analytics' && <Analytics api={api} />}
      {section === 'settings' && (
        <Settings
          api={api}
          theme={theme}
          onThemeChange={onThemeChange}
        />
      )}
      {section === 'friends' && <Friends api={api} />}
      {section === 'profile' && <Profile api={api} />}
      {section === 'games' && <Games wallet={wallet} />}
    </section>
  );
}
