import type { EconomyState, RendererApi, WalletSnapshot } from '@shared/types';
import Dashboard from './Dashboard';

type MoreView = 'analytics' | 'settings' | 'friends' | 'profile' | 'games';

type Props = {
  api: RendererApi;
  wallet: WalletSnapshot;
  economy: EconomyState | null;
  extensionStatus: { connected: boolean; lastSeen: number | null };
  productivityGoalHoursOverride?: number;
  onOpenShelf: () => void;
  onOpenFocus: () => void;
  onOpenMoreSection: (section: MoreView) => void;
};

export default function TodayView({
  api,
  wallet,
  economy,
  extensionStatus,
  productivityGoalHoursOverride,
  onOpenShelf,
  onOpenFocus,
  onOpenMoreSection
}: Props) {
  const currentSource = economy?.activeDomain ?? economy?.activeApp ?? 'Waiting for activity';
  const earnRate = economy?.activeCategory === 'productive'
    ? '+5/min'
    : economy?.activeCategory === 'neutral'
      ? '+3/min'
      : '0/min';

  return (
    <div className="today-view">
      <section className="today-studio">
        <div className="card today-status-card">
          <div className="card-header-row">
            <div>
              <p className="eyebrow">Companion</p>
              <h2>Keep the next action obvious</h2>
            </div>
            <span className="pill ghost">{wallet.balance} f-coins</span>
          </div>
          <div className="today-status-grid">
            <div>
              <span className="metric-label">Current mode</span>
              <strong>{economy?.activeCategory ?? 'idle'}</strong>
              <span className="subtle">{currentSource}</span>
            </div>
            <div>
              <span className="metric-label">Extension</span>
              <strong>{extensionStatus.connected ? 'Linked' : 'Offline'}</strong>
              <span className="subtle">
                {extensionStatus.connected
                  ? extensionStatus.lastSeen
                    ? `Last seen ${new Date(extensionStatus.lastSeen).toLocaleTimeString([], { hour: 'numeric', minute: '2-digit' })}`
                    : 'Browser paywalls are ready'
                  : 'Browser paywalls are paused'}
              </span>
            </div>
            <div>
              <span className="metric-label">Coin pace</span>
              <strong>{earnRate}</strong>
              <span className="subtle">Based on the current activity label</span>
            </div>
          </div>
        </div>

        <div className="today-actions">
          <button type="button" className="card today-action-card" onClick={onOpenFocus}>
            <p className="eyebrow">Focus</p>
            <strong>Start a writing or deep-work session</strong>
            <span className="subtle">Jump straight into the studio instead of browsing around.</span>
          </button>

          <button type="button" className="card today-action-card" onClick={onOpenShelf}>
            <p className="eyebrow">Shelf</p>
            <strong>Open better alternatives</strong>
            <span className="subtle">Treat the library like a nearby escape hatch, not a separate product.</span>
          </button>

          <button type="button" className="card today-action-card" onClick={() => onOpenMoreSection('analytics')}>
            <p className="eyebrow">Review</p>
            <strong>Check trends only when you need them</strong>
            <span className="subtle">History and deeper analytics live in More now.</span>
          </button>

          <button type="button" className="card today-action-card" onClick={() => onOpenMoreSection('settings')}>
            <p className="eyebrow">Tune</p>
            <strong>Adjust rules and thresholds</strong>
            <span className="subtle">Settings stay close, but out of the main flow.</span>
          </button>
        </div>
      </section>

      <Dashboard
        api={api}
        wallet={wallet}
        economy={economy}
        productivityGoalHoursOverride={productivityGoalHoursOverride}
        compact
      />
    </div>
  );
}
